  imports: [ IfxButton, IfxCard, IfxCardHeadline, IfxCardImage, IfxCardLinks, IfxCardOverline, IfxCardText, IfxTextField ],
  templateUrl: './ifx-card-example.html',
  styleUrl: './ifx-card-example.scss'
